// Read pipeline queue from /tmp/lead_queue.json and build status
const fs = require('fs');
const path = '/tmp/lead_queue.json';
const now = new Date().toISOString();

let queue = { cycles: 0, leads: [] };
try {
  queue = JSON.parse(fs.readFileSync(path, 'utf8'));
} catch (e) {
  // File doesn't exist yet — pipeline has not run
}

const leads = queue.leads || [];
const newLeads = leads.filter(l => l.status === 'new').length;
const processing = leads.filter(l => l.status === 'processing').length;
const dmSent = leads.filter(l => l.status === 'dm_sent').length;
const withEmail = leads.filter(l => l.email && l.email.includes('@')).length;

const currentPhase = dmSent > 0
  ? 'sending_dm'
  : processing > 0
    ? 'processing'
    : newLeads > 0
      ? 'finding_leads'
      : 'idle';

const response = {
  success: true,
  pipeline: {
    cycles_run: queue.cycles || 0,
    last_cycle: now,
    current_phase: currentPhase,
    pipeline_active: true,
    errors: [],
    leads_found_today: leads.length,
    total_leads_found: leads.length,
    total_onboarded: dmSent,
    total_dms_sent: dmSent,
    queue: {
      total: leads.length,
      new: newLeads,
      processing: processing,
      dm_sent: dmSent,
      with_email: withEmail
    }
  }
};

return response;
